[
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B",
    "type": "PERMITTED",
    "for": "the relevant local authority",
    "to": "give assistance to any person who qualifies for advice and assistance by virtue of section 24(1A) or section 24(2)(a) by contributing to expenses incurred by him in living near the place where he is, or will be, employed or seeking employment.",
    "conditions": []
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B",
    "type": "PERMITTED",
    "for": "the relevant local authority",
    "to": "give assistance to a person to whom subsection (3) applies by — (a)contributing to expenses incurred by the person in question in living near the place where he is, or will be, receiving education or training, or (b)making a grant to enable him to meet expenses connected with his education or training.",
    "conditions": []
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B",
    "type": "PERMITTED",
    "for": "the local authority",
    "to": "disregard any interruption in his attendance on the course if he resumes it as soon as is reasonably practicable",
    "conditions": [
      {
        "type": "WHEN/IF/WHERE",
        "text": "a local authority are assisting a person under subsection (2).",
        "section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B"
      }
    ]
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B",
    "type": "OBLIGATORY",
    "for": "the local authority",
    "to": "give a person to whom subsection (3) applies who is in full-time further or higher education assistance by — (a)providing him with suitable accommodation during the vacation or (b)paying him enough to enable him to secure such accommodation himself",
    "conditions": [
      {
        "type": "WHEN/IF/WHERE",
        "text": "the local authority are satisfied that the person needs accommodation during a vacation because his term-time accommodation is not available to him then.",
        "section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B"
      }
    ]
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24B",
    "type": "PERMITTED",
    "for": "the Secretary of State",
    "to": "prescribe the meaning of “ full-time ”, “ further education ”, “ higher education ” and “ vacation ” for the purposes of subsection (5).",
    "conditions": []
  }
]

[
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24D",
    "type": "OBLIGATORY",
    "for": "every local authority",
    "to": "establish a procedure for considering representations (including complaints) made to them by — (a)a relevant child for the purposes of section 23A or a young person falling within section 23C, (b)a person qualifying for advice and assistance or (c)a person falling within section 24B(2), about the discharge of their functions under this Part in relation to him.",
    "conditions": []
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24D",
    "type": "PERMITTED",
    "for": "the Secretary of State",
    "to": "make regulations imposing time limits on the making of representations under subsection (1).",
    "conditions": []
  },
  {
    "main_section": "https://www.legislation.gov.uk/ukpga/1989/41/section/24D",
    "type": "OBLIGATORY",
    "for": "a local authority",
    "to": "comply with regulations (if any) made by the Secretary of State for the purposes of this subsection",
    "conditions": [
