{
  "number": "32",
  "title": "Period within which application for order under this Part must be disposed of.",
  "subsections": {
    "section-32-1": {
      "number": "(1)",
      "content": "A courtin which an application for an order under this Part is proceedingshall (in the light of anyprovision in rules of court that is of the kind mentioned in subsection (2)(a) or (b))—",
      "subitems": {
        "section-32-1-a": {
          "number": "(a)",
          "content": "draw up a timetable with a view todisposing of the application—"
        },
        "section-32-1-b": {
          "number": "(b)",
          "content": "give such directions as it considers appropriate for the purpose of ensuring, so far as is reasonably practicable, that that timetable is adhered to."
        }
      },
      "additional_content": [
        "without delay, and",
        "in any event within twenty-six weeks beginning with the day on which the application was issued; and"
      ]
    },
    "section-32-2": {
      "number": "(2)",
      "content": "Rules of court may—",
      "subitems": {
        "section-32-2-a": {
          "number": "(a)",
          "content": "specify periods within which specified steps must be taken in relation to such proceedings; and"
        },
        "section-32-2-b": {
          "number": "(b)",
          "content": "make other provision with respect to such proceedings for the purpose of ensuring, so far as is reasonably practicable, that they are disposed of without delay."
        }
      }
    },
    "section-32-3": {
      "number": "(3)",
      "content": "A court, when drawing up a timetable under subsection (1)(a), must in particular have regard to—",
      "subitems": {
        "section-32-3-a": {
          "number": "(a)",
          "content": "the impact which the timetable would have on the welfare of the child to whom the application relates; and"
        },
        "section-32-3-b": {
          "number": "(b)",
          "content": "the impact which the timetable would have on the conduct of the proceedings."
        }
      }
    },
    "section-32-4": {
      "number": "(4)",
      "content": "A court, when revising a timetable drawn up under subsection (1)(a) or when making any decision which may give rise to a need to revise such a timetable (which does not include a decision under subsection (5)), must in particular have regard to—",
      "subitems": {
        "section-32-4-a": {
          "number": "(a)",
          "content": "the impact which any revision would have on the welfare of the child to whom the application relates; and"
        },
        "section-32-4-b": {
          "number": "(b)",
          "content": "the impact which any revision would have on the duration and conduct of the proceedings."
        }
      }
    },
    "section-32-5": {
      "number": "(5)",
      "content": "A court in which an application under this Part is proceeding may extend the period that is for the time being allowed under subsection (1)(a)(ii) in the case of the application, but may do so only if the court considers that the extension is necessary to enable the court to resolve the proceedings justly."
    },
    "section-32-6": {
      "number": "(6)",
      "content": "When deciding whether to grant an extension under subsection (5), a court must in particular have regard to—",
      "subitems": {
        "section-32-6-a": {
          "number": "(a)",
          "content": "the impact which any ensuing timetable revision would have on the welfare of the child to whom the application relates, and"
        },
        "section-32-6-b": {
          "number": "(b)",
          "content": "the impact which any ensuing timetable revision would have on the duration and conduct of the proceedings;"
        }
      },
      "additional_content": "and here “ensuing timetable revision” means any revision, of the timetable under subsection (1)(a) for the proceedings, which the court considers may ensue from the extension."
    },
    "section-32-7": {
      "number": "(7)",
      "content": "When deciding whether to grant an extension under subsection (5), a court is to take account of the following guidance: extensions are not to be granted routinely and are to be seen as requiring specific justification."
    },
    "section-32-8": {
      "number": "(8)",
      "content": "Each separate extension under subsection (5) is to end no more than eight weeks after the later of—",
      "subitems": {
        "section-32-8-a": {
          "number": "(a)",
          "content": "the end of the period being extended; and"
        },
        "section-32-8-b": {
          "number": "(b)",
          "content": "the end of the day on which the extension is granted."
        }
      }
    },
    "section-32-9": {
      "number": "(9)",
      "content": "The Lord Chancellor may by regulations amend subsection (1)(a)(ii), or the opening words of subsection (8), for the purpose of varying the period for the time being specified in that provision."
    },
    "section-32-10": {
      "number": "(10)",
      "content": "Rules of court may provide that a court—",
      "subitems": {
        "section-32-10-a": {
          "number": "(a)",
          "content": "when deciding whether to exercise the power under subsection (5), or"
        },
        "section-32-10-b": {
          "number": "(b)",
          "content": "when deciding how to exercise that power,"
        }
      },
      "additional_content": "must, or may or may not, have regard to matters specified in the rules, or must take account of any guidance set out in the rules."
    }
  }
}

